              <QrCode className="h-4 w-4 inline mr-1" /> QR
            </button>
            <button onClick={() => setMode('manual')} className={`flex-1 py-2 text-sm font-medium ${mode === 'manual' ? 'bg-rose-500 text-white' : ''}`}>
              <User className="h-4 w-4 inline mr-1" /> CI Manual
            </button>
          </div>

