{"content": "import { NextResponse, type NextRequest } from 'next/server';

export async function middleware(request: NextRequest) {
  const pathname = request.nextUrl.pathname;

  // Only check auth for /admin routes  
  if (!pathname.startsWith('/admin')) {
    return NextResponse.next({ request });
  }

  // Allow login page and static assets through
  if (pathname === '/admin/ingreso' ||
      pathname.startsWith('/_next/') ||
      pathname.startsWith('/api/')) {
    return NextResponse.next({ request });
  }

  const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL;
  const supabaseAnonKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY;

  // Skip auth if env is missing (self-hosted mode)
  if (!supabaseUrl || !supabaseAnonKey || !supabaseUrl.includes('supabase.co')) {
    return NextResponse.next({ request });
  }

  try {
    const { createServerClient } = await import('@supabase/ssr');
    let supabaseResponse = NextResponse.next({ request });

    const supabase = createServerClient(supabaseUrl, supabaseAnonKey, {
      cookies: {
        getAll() { return request.cookies.getAll(); },
        setAll(cookiesToSet) {
          cookiesToSet.forEach(({ name, value }) => request.cookies.set(name, value));
          supabaseResponse = NextResponse.next({ request });
          cookiesToSet.forEach(({ name, value, options }) =>
            supabaseResponse.cookies.set(name, value, options)
          );
        },
      },
    });

    const { data: { user } } = await supabase.auth.getUser();

    if (!user) {
      const url = request.nextUrl.clone();
      url.pathname = '/admin/ingreso';
      url.searchParams.set('redirect', pathname);
      return NextResponse.redirect(url);
    }

    return supabaseResponse;
  } catch {
    return NextResponse.next({ request });
  }
}

export const config = {
  matcher: ['/admin/:path*'],
};
