// Falls back to mock client when no real Supabase REST API is available

import { createClient } from '@supabase/supabase-js'

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL || ''
const supabaseAnonKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY || ''
const isSelfHosted = !supabaseUrl.includes('supabase.co')

export function createBrowserClient() {
  // For self-hosted, the browser client won't have auth/REST
  // but the server-side API routes handle DB access directly
  return createClient(supabaseUrl, supabaseAnonKey, {
    auth: {
      autoRefreshToken: true,
      persistSession: true,
      detectSessionInUrl: true,
    },
  })
}

