  --sidebar: #261B28;
  --sidebar-foreground: #EADEE8;
  --sidebar-primary: #C98DC4;
  --sidebar-primary-foreground: #1A101C;
  --sidebar-accent: #3D2A40;
  --sidebar-accent-foreground: #EADEE8;
  --sidebar-border: #3D2A40;
  --sidebar-ring: #C98DC4;
  --surface: #261B28;
  --surface-light: #3D2A40;
  --success: #66BB8A;
  --warning: #FFA726;
}

@layer base {
  * { @apply border-border outline-ring/50; }
  body { @apply bg-background text-foreground antialiased; }
  html { scroll-behavior: smooth; }

  /* ♿ Focus styles */
  :focus-visible { @apply outline-2 outline-offset-2 outline-ring; }
  a { @apply text-accent underline decoration-accent/30 underline-offset-2 hover:decoration-accent transition-all duration-200; }
  a:focus-visible { @apply outline-2 outline-offset-2; }

  /* ♿ Skip link */
  .skip-link { @apply sr-only focus:not-sr-only focus:fixed focus:top-4 focus:left-4 focus:z-[9999] focus:bg-primary focus:text-primary-foreground focus:px-4 focus:py-2 focus:rounded-lg focus:text-sm focus:font-semibold; }

  /* Better heading hierarchy */
  h1 { @apply text-3xl md:text-4xl font-extrabold tracking-tight; }
  h2 { @apply text-2xl md:text-3xl font-bold tracking-tight; }
  h3 { @apply text-xl font-semibold; }

  /* Better text contrast */
  p { @apply leading-relaxed; }
}
